import face_recognition
from flask import Flask, request, jsonify
import numpy as np
from sklearn.svm import SVC
from PIL import Image, ImageDraw

app = Flask(__name__)

# Load employee photos and encode faces
employees = ["Employee1.jpg", "Employee2.jpg"]
known_face_encodings = []
for employee in employees:
    image = face_recognition.load_image_file(employee)
    face_encoding = face_recognition.face_encodings(image)[0]
    known_face_encodings.append(face_encoding)

# Train model using SVM
clf = SVC(probability=True, kernel='rbf', C=1.0)
clf.fit(known_face_encodings[:], np.zeros((len(employees),)))

@app.route('/face-recognition', methods=['POST'])
def face_recognition():
    # Get image from request
    image = request.files['image']
    
    # Encode faces in the image
    unknown_image = face_recognition.load_image_file(image)
    face_locations = face_recognition.face_locations(unknown_image)
    face_encodings = face_recognition.face_encodings(unknown_image, face_locations)

    # Predict confidence scores and probabilities
    results = clf.predict_proba(face_encodings)
    
    # Get detailed probability distribution over all known faces
    class_probabilities = []
    for result in results:
        max_confidence = 0
        best_match = None
        for i, employee in enumerate(employees):
            distance = np.linalg.norm(result - known_face_encodings[i])
            if distance < 0.6 and distance > max_confidence:
                max_confidence = distance
                best_match = employee
        class_probabilities.append(max_confidence)
    
    # Return confidence scores and detailed probability distribution as JSON
    return jsonify({
        'confidence_scores': [result[0] for result in results],
        'detailed_probability_distribution': {
            employees[i]: probability if i < len(employees) else None
            for i, probability in enumerate(class_probabilities)
        }
    })

if __name__ == '__main__':
    app.run(debug=True)